// Debug: inspect what's in each input
const geozoItems = $('Fetch Geo Stats (7 days)').all();
const crmItems = $('Fetch CRM Leads by Geo').all().map(i => i.json);

// Try to find the stats array from Geozo API response
// The HTTP node returns parsed JSON. Structure could be:
// 1. {data: {result: {data: [...]}}} - nested
// 2. {result: {data: [...]}} - semi-nested
// 3. [{...}, {...}] - items already split by n8n
// 4. {data: [...]} - simple wrapper
let stats = [];

if (geozoItems.length === 1) {
  // Single item = entire API response as one object
  const raw = geozoItems[0].json;
  stats = raw?.data?.result?.data
    || raw?.result?.data
    || raw?.data
    || (Array.isArray(raw) ? raw : []);
} else if (geozoItems.length > 1) {
  // Multiple items = n8n already split the array
  // Check if first item looks like a stat row (has ad_id)
  if (geozoItems[0].json?.ad_id || geozoItems[0].json?.country_code) {
    stats = geozoItems.map(i => i.json);
  } else {
    // Try nested on first item
    const raw = geozoItems[0].json;
    stats = raw?.data?.result?.data || raw?.result?.data || raw?.data || [];
  }
}

if (!Array.isArray(stats) || stats.length === 0) {
  // Return debug info so we can see what the API returned
  const raw = geozoItems[0]?.json || {};
  const keys = Object.keys(raw);
  const sample = JSON.stringify(raw).slice(0, 500);
  return [{ json: {
    action: 'DEBUG_NO_STATS',
    geozo_items_count: geozoItems.length,
    first_item_keys: keys,
    first_item_sample: sample,
    crm_items_count: crmItems.length
  } }];
}

// Build CRM map: ad_id+geo -> {leads, depositors, revenue}
const crmMap = {};
crmItems.forEach(row => {
  const key = `${row.ad_id}_${(row.geo || '').toUpperCase()}`;
  crmMap[key] = {
    leads: Number(row.total_leads) || 0,
    depositors: Number(row.depositors) || 0,
    revenue: Number(row.crm_revenue) || 0
  };
});

const results = [];
stats.forEach(d => {
  const adId = d.ad_id;
  const country = d.country_code;
  if (!adId || !country) return;

  const spend = Number(d.money) || 0;
  const key = `${adId}_${country.toUpperCase()}`;
  const crm = crmMap[key] || { leads: 0, depositors: 0, revenue: 0 };
  const roi = spend > 0 ? Math.round((crm.revenue - spend) / spend * 10000) / 100 : 0;
  const cpl = crm.leads > 0 ? Math.round(spend / crm.leads * 100) / 100 : 0;

  results.push({
    json: {
      ad_id: adId,
      country_code: country,
      shows: Number(d.shows_count) || 0,
      clicks: Number(d.clicks_count) || 0,
      spend: Math.round(spend * 100) / 100,
      revenue: Math.round(crm.revenue * 100) / 100,
      leads: crm.leads,
      depositors: crm.depositors,
      cpl: cpl,
      roi: roi
    }
  });
});

// Add debug first item for verification
const debugItem = stats[0] || {};
results.unshift({ json: {
  _debug: true,
  _stats_count: stats.length,
  _crm_count: crmItems.length,
  _first_stat_keys: Object.keys(debugItem),
  _first_stat_sample: JSON.stringify(debugItem).slice(0, 300),
  ad_id: 0,
  country_code: 'DEBUG',
  shows: 0, clicks: 0, spend: 0, revenue: 0, leads: 0, depositors: 0, cpl: 0, roi: 0
} });

return results;
